func TestEnumFileInfo(t *testing.T) {
	t.Run("NewFromString_REGULAR", func(t *testing.T) {
		t.Parallel()
		val, err := NewFileInfoFromString("REGULAR")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, FileInfo("REGULAR"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_DIRECTORY", func(t *testing.T) {
		t.Parallel()
		val, err := NewFileInfoFromString("DIRECTORY")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, FileInfo("DIRECTORY"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewFileInfoFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewFileInfoFromString("REGULAR")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

